import LogoSDQ from '../components/LogoSDQ';
import { User } from '../types';

// Fix: Define props for Login component to handle optional onLogin callback
interface LoginProps {
  onLogin?: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [role, setRole] = useState<'KOORDINATOR' | 'GURU'>('GURU');
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();

    // Create mock user object to pass to onLogin callback
    const mockUser: User = {
      id: role === 'KOORDINATOR' ? 'mock-koordinator' : 'mock-guru',
      email: email,
      name: role === 'KOORDINATOR' ? 'Ustadz Umar (Demo)' : 'Ustadz Ahmad (Demo)',
      role: role
    };

    if (onLogin) {
      onLogin(mockUser);
    }

    if (role === 'KOORDINATOR') navigate('/coordinator');
    else navigate('/guru');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 p-6">
      <div className="w-full max-w-md">
        <div className="bg-white p-8 rounded-2xl shadow-xl border border-gray-100">
          <div className="flex flex-col items-center mb-10 text-center">
            <LogoSDQ className="h-16 w-auto mb-4" />
            <h1 className="text-2xl font-bold text-gray-900">Selamat Datang</h1>
            <p className="text-gray-500">Silakan masuk ke akun Anda</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Peran</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  type="button"
                  onClick={() => setRole('GURU')}
                  className={`py-3 px-4 rounded-xl border-2 transition-all ${role === 'GURU' ? 'border-emerald-500 bg-emerald-50 text-emerald-700 font-bold' : 'border-gray-200 bg-white text-gray-500'}`}
                >
                  Guru
                </button>
                <button 
                  type="button"
                  onClick={() => setRole('KOORDINATOR')}
                  className={`py-3 px-4 rounded-xl border-2 transition-all ${role === 'KOORDINATOR' ? 'border-emerald-500 bg-emerald-50 text-emerald-700 font-bold' : 'border-gray-200 bg-white text-gray-500'}`}
                >
                  Koordinator
                </button>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Email</label>
              <Input 
                type="email" 
                placeholder="ustadz@sdq.school" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Kata Sandi</label>
              <Input type="password" placeholder="••••••••" required />
            </div>

            <Button type="submit" className="w-full py-3 text-lg">Masuk Sekarang</Button>
          </form>

          <div className="mt-8 text-center">
            <p className="text-sm text-gray-500">Lupa kata sandi? Hubungi admin IT SDQ</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

import { GoogleGenAI } from "@google/genai";
import { Student } from "../../../types";

// Initialize Gemini API client using correct configuration
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function POST(student: Student) {
  try {
    const prompt = `
      You are an expert Quranic teacher and mentor at an Islamic school (SDQ).
      Please write a supportive, encouraging, and constructive evaluation report for a student.
      Use a formal yet warm tone (Bahasa Indonesia).

      Student Data:
      - Name: ${student.name}
      - Class: ${student.className}
      - Target: ${student.memorizationTarget}
      - Current Progress: ${student.currentProgress}
      - Attendance: ${student.attendance}%
      - Behavior Score: ${student.behaviorScore}/10

      Structure the report with:
      1. Overall Performance (Pencapaian Umum)
      2. Strengths (Kelebihan)
      3. Areas for Improvement (Area yang Perlu Ditingkatkan)
      4. Message for Parents (Pesan untuk Orang Tua)

      Keep it concise (under 200 words).
    `;

    // Using recommended model for Basic Text Tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // Directly accessing .text property as per guidelines
    return response.text || "Mohon maaf, evaluasi tidak dapat dibuat saat ini.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Terjadi kesalahan saat menghubungi layanan AI.");
  }
}

