import { Student } from '../types';

export interface SDQProgressResult {
  current: number;
  target: number;
  percentage: number;
  unit: string; // "Juz" atau "Jilid"
  colorClass: string;
  label: string; // e.g., "2 dari 3 Juz"
  statusText: string;
  classLevel: number;
}

// TARGET RESMI SDQ PER KELAS
const SDQ_TARGETS: Record<number, number> = {
  1: 6, // Target: Iqra 1-6
  2: 1, // Target: 1 Juz (Juz 30)
  3: 3, // Target: 3 Juz
  4: 4, // Target: 4 Juz
  5: 5, // Target: 5 Juz
  6: 5  // Target: 5 Juz
};

// KONSTANTA KONVERSI
const PAGES_PER_JUZ = 20;
const LINES_PER_PAGE = 15;
const LINES_PER_JUZ = PAGES_PER_JUZ * LINES_PER_PAGE; // 300 Baris

/**
 * LOGIKA SISTEM: Mengekstrak ANGKA kelas dari string nama kelas.
 */
export const extractClassLevel = (input: any): number => {
  if (!input) return 0;
  if (typeof input === 'number') {
    return (input >= 1 && input <= 6) ? input : 0;
  }
  const str = String(input).trim();
  const matchStandard = str.match(/Kelas\s*(\d+)/i);
  if (matchStandard && matchStandard[1]) {
    const level = parseInt(matchStandard[1], 10);
    return (level >= 1 && level <= 6) ? level : 0;
  }
  const matchStart = str.match(/^(\d+)/);
  if (matchStart && matchStart[1]) {
    const level = parseInt(matchStart[1], 10);
    return (level >= 1 && level <= 6) ? level : 0;
  }
  return 0;
};

/**
 * Helper: Hitung progress Iqra untuk Kelas 1
 */
const getCompletedIqra = (progressStr: string): number => {
  if (!progressStr || progressStr === 'Belum Ada' || progressStr === '-') return 0;
  const lower = progressStr.toLowerCase();

  if (!lower.includes('iqra') && !lower.includes('jilid')) {
    return 6; // Lulus Iqra (Masuk Al-Quran)
  }

  const match = lower.match(/iqra\s*'?\s*(\d+)/i);
  if (match) {
    const currentVolume = parseInt(match[1]);
    return Math.max(0, currentVolume - 1);
  }
  return 0;
};

/**
 * Helper: Konversi Total Hafalan (Juz, Hal, Baris) menjadi Juz Desimal
 * Contoh: 0 Juz, 10 Halaman -> 0.5 Juz
 */
const convertToDecimalJuz = (total: { juz?: number, pages?: number, lines?: number } | undefined): number => {
  if (!total) return 0;

  const juz = Number(total.juz || 0);
  const pages = Number(total.pages || 0);
  const lines = Number(total.lines || 0);

  // Rumus: Juz + (Halaman / 20) + (Baris / 300)
  const decimalValue = juz + (pages / PAGES_PER_JUZ) + (lines / LINES_PER_JUZ);

  // Pembulatan 2 desimal agar rapi (misal 0.25)
  return Math.round(decimalValue * 100) / 100;
};

/**
 * FUNGSI UTAMA (SINGLE SOURCE OF TRUTH)
 */
export const calculateSDQProgress = (student: Student): SDQProgressResult => {
  // 1. TENTUKAN CLASS LEVEL
  let level = student.classLevel || 0;
  if (level === 0) level = extractClassLevel(student.className);
  if (level === 0) {
    const rawData = student as any;
    if (rawData.kelas) level = extractClassLevel(rawData.kelas);
    else if (rawData.namaKelas) level = extractClassLevel(rawData.namaKelas);
  }

  if (level === 0) {
    return {
      classLevel: 0,
      target: 0,
      current: 0,
      percentage: 0,
      unit: '-',
      colorClass: "bg-gray-400", 
      statusText: "Kelas Tidak Valid",
      label: "Data Kelas Error"
    };
  }

  // 2. TENTUKAN TARGET
  const target = SDQ_TARGETS[level] || 1;

  // 3. HITUNG CAPAIAN (CURRENT)
  let current = 0;
  let unit = "Juz";

  if (level === 1) {
    // --- LOGIKA KELAS 1: IQRA ---
    unit = "Jilid";
    current = getCompletedIqra(student.currentProgress);
  } else {
    // --- LOGIKA KELAS 2-6: TAHFIZH JUZ (DECIMAL) ---
    unit = "Juz";
    // UPDATE: Gunakan fungsi konversi desimal, bukan hanya ambil juz bulat
    current = convertToDecimalJuz(student.totalHafalan);
  }

  // 4. HITUNG PERSENTASE
  // Rumus: (Capaian Desimal / Target) * 100
  let percentage = Math.round((current / target) * 100);

  // Cap maksimal 100% untuk visual bar (tapi angka boleh lebih untuk badge)
  const visualPercentage = Math.min(percentage, 100);

  // 5. TENTUKAN WARNA & STATUS
  let colorClass = "";
  let statusText = "";

  if (percentage >= 100) {
    colorClass = "bg-green-500"; 
    statusText = "Target Tercapai";
  } else if (percentage >= 80) {
    colorClass = "bg-blue-500"; 
    statusText = "Hampir Tercapai";
  } else if (percentage >= 50) {
    colorClass = "bg-orange-500"; 
    statusText = "Perlu Dorongan";
  } else {
    colorClass = "bg-red-500"; 
    statusText = "Perlu Perhatian";
  }

  // 6. RETURN OBJECT
  return {
    classLevel: level,
    target,
    current, // Return float (misal 0.25) agar info akurat
    unit,
    percentage,
    colorClass,
    statusText,
    // Label akan menampilkan desimal jika ada pecahan, misal "0.5 dari 1 Juz"
    label: `${current} dari ${target} ${unit}`
  };
};

