rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    // --- HELPER FUNCTIONS ---

    // Cek apakah user sudah login
    function isAuthenticated() {
      return request.auth != null;
    }

    // Ambil data user dari collection 'users'
    function getUserData() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data;
    }

    // Cek Role Koordinator
    function isKoordinator() {
      return isAuthenticated() && getUserData().role == 'KOORDINATOR';
    }

    // Cek Role Guru
    function isGuru() {
      return isAuthenticated() && getUserData().role == 'GURU';
    }

    // Cek apakah data yang diakses milik Guru yang sedang login
    // Digunakan untuk READ/UPDATE/DELETE
    function isOwner(resourceData) {
      return resourceData.teacherId == request.auth.uid;
    }

    // Cek apakah data baru yang akan dibuat ditetapkan untuk diri sendiri
    // Digunakan untuk CREATE
    function isAssigningSelf() {
      return request.resource.data.teacherId == request.auth.uid;
    }

    // --- COLLECTION RULES ---

    // 1. Users Collection
    match /users/{userId} {
      // Koordinator bisa baca semua, User bisa baca profil sendiri
      allow read: if isKoordinator() || (isAuthenticated() && request.auth.uid == userId);

      // Hanya Koordinator yang bisa membuat/mengedit user (assign role)
      allow write: if isKoordinator();
    }

    // 2. Kelas Collection (Reference Data)
    match /kelas/{classId} {
      // Semua user terautentikasi butuh baca kelas untuk Dropdown
      allow read: if isAuthenticated();
      // Hanya koordinator yang mengatur struktur kelas
      allow write: if isKoordinator();
    }

    // 3. Halaqah Collection
    match /halaqah/{halaqahId} {
      // Koordinator baca semua, Guru baca halaqah miliknya saja
      allow read: if isKoordinator() || (isGuru() && isOwner(resource.data));
      // Struktur halaqah diatur koordinator
      allow write: if isKoordinator();
    }

    // 4. Siswa Collection
    match /siswa/{studentId} {
      // Read: Koordinator atau Guru pemilik siswa tersebut
      allow read: if isKoordinator() || (isGuru() && isOwner(resource.data));

      // Create: Koordinator atau Guru (tapi Guru wajib set teacherId ke diri sendiri)
      allow create: if isKoordinator() || (isGuru() && isAssigningSelf());

      // Update/Delete: Koordinator atau Guru pemilik
      allow update: if isKoordinator() || (isGuru() && isOwner(resource.data) && isAssigningSelf());
      allow delete: if isKoordinator() || (isGuru() && isOwner(resource.data));
    }

    // 5. Laporan & Evaluasi Collection
    // Menggunakan wildcard karena logic-nya sama persis
    match /{collection}/{docId} {
      allow read: if (collection == 'laporan' || collection == 'evaluasi') && 
                  (isKoordinator() || (isGuru() && isOwner(resource.data)));

      allow create: if (collection == 'laporan' || collection == 'evaluasi') && 
                    (isKoordinator() || (isGuru() && isAssigningSelf()));

      allow update: if (collection == 'laporan' || collection == 'evaluasi') && 
                    (isKoordinator() || (isGuru() && isOwner(resource.data)));

      allow delete: if (collection == 'laporan' || collection == 'evaluasi') && 
                    (isKoordinator() || (isGuru() && isOwner(resource.data)));
    }
  }
}

