import { GoogleGenAI } from "@google/genai";
import { Student } from "../types";

/**
 * Inisialisasi Gemini Client menggunakan import.meta.env standar Vite.
 * Pastikan VITE_GEMINI_API_KEY sudah diset di Vercel Dashboard.
 */
const getAiClient = () => {
  const apiKey = import.meta.env.VITE_GEMINI_API_KEY;
  if (!apiKey) {
    throw new Error("Gemini API Key is missing. Check VITE_GEMINI_API_KEY in environment.");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateStudentEvaluation = async (student: Student): Promise<string> => {
  try {
    const ai = getAiClient();

    const prompt = `
      Anda adalah pakar pendidik Al-Qur'an.
      Buatlah evaluasi naratif yang mendukung untuk siswa berikut:
      Nama: ${student.name}
      Kelas: ${student.className}
      Target: ${student.memorizationTarget}
      Progres: ${student.currentProgress}

      Berikan masukan konstruktif dalam Bahasa Indonesia yang hangat.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Evaluasi tidak dapat dibuat saat ini.";
  } catch (error) {
    console.error("Gemini Service Error:", error);
    return "Gagal menghubungi layanan AI. Pastikan API Key valid.";
  }
};

import { 
  collection, 
  getDocs, 
  addDoc, 
  query, 
  where, 
  doc, 
  getDoc,
  updateDoc,
  serverTimestamp,
  writeBatch,
  onSnapshot,
  Unsubscribe,
  orderBy
} from 'firebase/firestore';
import { db } from '../lib/firebase';
import { User, Student, Report, Role } from '../types';
import { extractClassLevel } from './sdqTargets';

export const getAllTeachers = async (): Promise<User[]> => {
  if (!db) return [];
  try {
    const snapshot = await getDocs(collection(db, 'users'));
    return snapshot.docs.map(doc => {
      const data = doc.data();
      return {
        id: doc.id,
        name: data.name || "Tanpa Nama",
        nickname: data.nickname || "",
        email: data.email || "",
        role: data.role || "GURU",
        photoURL: data.photoURL || "",
      } as User;
    });
  } catch (error) {
    console.error("Error fetching teachers:", error);
    return [];
  }
};

export const getTeacherById = async (id: string): Promise<User | undefined> => {
  if (!db) return undefined;
  try {
    const docRef = doc(db, 'users', id);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) {
      return { id: docSnap.id, ...docSnap.data() } as User;
    }
    return undefined;
  } catch (error) {
    console.error("Error fetching teacher:", error);
    return undefined;
  }
};

export const addTeacher = async (name: string, email: string, nickname: string, role: Role): Promise<User> => {
  if (!db) throw new Error("Firestore not initialized");

  const newUser = {
    name,
    nickname,
    email,
    role,
    createdAt: serverTimestamp()
  };

  const docRef = await addDoc(collection(db, 'users'), newUser);

  // // Fix: Use a string timestamp for the return object to satisfy the User interface requirements
  return {
    id: docRef.id,
    name,
    nickname,
    email,
    role,
    createdAt: new Date().toISOString()
  } as User;
};

