  if (!db) return () => {}; 
  const q = query(collection(db, 'siswa'), where('teacherId', '==', teacherId));
  return onSnapshot(q, (snapshot) => {
    const students = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
    onUpdate(students);
  });
};

export const subscribeToReportsByTeacher = (
  teacherId: string,
  onUpdate: (reports: Report[]) => void
): Unsubscribe => {
  if (!db) return () => {};
  const q = query(collection(db, 'laporan'), where('teacherId', '==', teacherId));
  return onSnapshot(q, (snapshot) => {
    const reports = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Report));
    onUpdate(reports);
  });
};

export const addStudent = async (student: Omit<Student, 'id' | 'attendance' | 'behaviorScore'>): Promise<Student> => {
  if (!db) throw new Error("Firestore not initialized");
  const level = extractClassLevel(student.className);
  const docRef = await addDoc(collection(db, 'siswa'), { ...student, classLevel: level, attendance: 100, behaviorScore: 10, createdAt: serverTimestamp() });
  return { id: docRef.id, ...student, classLevel: level, attendance: 100, behaviorScore: 10, createdAt: new Date().toISOString() } as Student;
};

export const updateStudent = async (id: string, data: Partial<Student>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'siswa', id);
  const updateData = { ...data };

  if (data.className) {
    (updateData as any).classLevel = extractClassLevel(data.className);
  }

  await updateDoc(docRef, updateData);
};

export const addReport = async (report: Omit<Report, 'id' | 'createdAt'>): Promise<Report> => {
  if (!db) throw new Error("Firestore not initialized");
  const batch = writeBatch(db);
  const newReportRef = doc(collection(db, 'laporan'));
  const createdAt = new Date().toISOString();
  batch.set(newReportRef, { ...report, createdAt });

  const studentRef = doc(db, 'siswa', report.studentId);
  const latestProgress = report.tahfizh.individual.split(' - ')[1] || report.tahfizh.individual;
  batch.update(studentRef, { 
    currentProgress: latestProgress,
    ...(report.totalHafalan ? { totalHafalan: report.totalHafalan } : {})
  });

  await batch.commit();
  return { id: newReportRef.id, ...report, createdAt } as Report;
};

export const getAllStudents = async (): Promise<Student[]> => {
  if (!db) return [];
  const snapshot = await getDocs(collection(db, 'siswa'));
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
};

import React, { useEffect, useState, useRef } from 'react';
import { Student, User } from '../../../types';
import { getAllStudents, getAllTeachers, addStudent, updateStudent } from '../../../services/firestoreService';
import { CLASS_LIST } from '../../../services/mockBackend';
import { Button } from '../../../components/Button';
import { Search, Filter, Download, Plus, X, Upload } from 'lucide-react';
import * as XLSX from 'xlsx';

export default function CoordinatorSiswaPage() {
  const [students, setStudents] = useState<Student[]>([]);
  const [filteredStudents, setFilteredStudents] = useState<Student[]>([]);
  const [teachers, setTeachers] = useState<User[]>([]);
  const [search, setSearch] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Import State
  const [isImporting, setIsImporting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    nis: '',
    nisn: '',
    className: '',
    teacherId: '',
    memorizationTarget: 'Juz 30',
    currentProgress: 'Belum Ada'
  });

  // Helper map for teacher names
  const [teacherMap, setTeacherMap] = useState<Record<string, string>>({});

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setIsLoading(true);
    const [allStudents, allTeachers] = await Promise.all([
      getAllStudents(),
      getAllTeachers()
    ]);

    setTeachers(allTeachers);

    const tMap: Record<string, string> = {};
    allTeachers.forEach(t => tMap[t.id] = t.name);
    setTeacherMap(tMap);

    setStudents(allStudents);
    setFilteredStudents(allStudents);
    setIsLoading(false);
  };

  useEffect(() => {
    const lowerSearch = search.toLowerCase();
    const filtered = students.filter(s => 
      s.name.toLowerCase().includes(lowerSearch) || 
      (s.className && s.className.toLowerCase().includes(lowerSearch)) ||
      (s.nis && s.nis.includes(lowerSearch)) ||
      (s.nisn && s.nisn.includes(lowerSearch))
    );
    setFilteredStudents(filtered);
  }, [search, students]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleOpenAddModal = () => {
    setEditingId(null);
    setFormData({
      name: '',
      nis: '',
      nisn: '',
      className: '',
      teacherId: '',
      memorizationTarget: 'Juz 30',
      currentProgress: 'Belum Ada'
    });
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (student: Student) => {
    setEditingId(student.id);
    setFormData({
      name: student.name,
      nis: student.nis || '',
      nisn: student.nisn || '',
      className: student.className,
      teacherId: student.teacherId,
      memorizationTarget: student.memorizationTarget,
      currentProgress: student.currentProgress
    });
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.className || !formData.teacherId) {
      alert("Mohon lengkapi data wajib (Nama, Kelas, Guru)");
      return;
    }

    setIsSubmitting(true);
    try {
      if (editingId) {
        // Update existing student
        await updateStudent(editingId, {
          ...formData
        });
      } else {
        // Add new student
        await addStudent({
          ...formData,
          classId: '',
          progress: 0
        });
      }

      await loadData(); // Reload from Firestore
      setIsModalOpen(false);
    } catch (error) {
      console.error(error);
      alert("Gagal menyimpan data siswa ke database.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // --- IMPORT EXCEL LOGIC ---
  const handleImportClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);

    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data);
      const sheetName = workbook.SheetNames[0];
      const sheet = workbook.Sheets[sheetName];
      const jsonData = XLSX.utils.sheet_to_json(sheet);

      if (jsonData.length === 0) {
        alert("File Excel kosong atau format tidak sesuai.");
        setIsImporting(false);
        return;
      }

      let successCount = 0;
      let failCount = 0;

      for (const row of jsonData as any[]) {
        const name = row['Nama'] || row['nama'];
        const nis = row['NIS'] || row['nis'] || '';
        const nisn = row['NISN'] || row['nisn'] || '';
        const className = row['Kelas'] || row['kelas'];
        const target = row['Target'] || row['target'] || 'Juz 30';
        const teacherName = row['Guru'] || row['guru'];

        if (!name || !className || !teacherName) {
          failCount++;
          continue;
        }

        const matchedTeacher = teachers.find(t => 
          t.name.toLowerCase().includes(teacherName.toLowerCase()) || 
          (t.nickname && t.nickname.toLowerCase().includes(teacherName.toLowerCase()))
        );

        if (!matchedTeacher) {
          failCount++;
          continue;
        }

        await addStudent({
          name: String(name),
          nis: String(nis),
          nisn: String(nisn),
          className: String(className),
          teacherId: matchedTeacher.id,
          memorizationTarget: String(target),
          currentProgress: 'Belum Ada',
          classId: '',
          progress: 0
        });

        successCount++;
      }

      alert(`Proses Import Selesai.\nBerhasil: ${successCount}\nGagal: ${failCount}`);
      await loadData();

    } catch (error) {
      console.error("Import Error:", error);
      alert("Terjadi kesalahan saat membaca file Excel.");
    } finally {
