        ></textarea>
      </div>

      <div className="flex justify-end">
        <Button onClick={handleSave} className="w-full sm:w-auto px-8 py-3" isLoading={isSaving}>Simpan Laporan</Button>
      </div>
    </div>
  );
}

import { 
  collection, 
  getDocs, 
  addDoc, 
  query, 
  where, 
  doc, 
  getDoc,
  updateDoc,
  serverTimestamp,
  writeBatch,
  onSnapshot,
  Unsubscribe
} from 'firebase/firestore';
import { db } from '../lib/firebase';
import { User, Student, Report, Role } from '../types';
import { extractClassLevel } from './sdqTargets';

export const getAllTeachers = async (): Promise<User[]> => {
  if (!db) return [];
  const snapshot = await getDocs(collection(db, 'users'));
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
};

export const getTeacherById = async (id: string): Promise<User | undefined> => {
  if (!db) return undefined;
  const docRef = doc(db, 'users', id);
  const docSnap = await getDoc(docRef);
  return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } as User : undefined;
};

export const addTeacher = async (name: string, email: string, nickname: string, role: Role): Promise<User> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = await addDoc(collection(db, 'users'), { name, nickname, email, role, createdAt: serverTimestamp() });
  return { id: docRef.id, name, nickname, email, role, createdAt: new Date().toISOString() } as User;
};

export const updateTeacher = async (id: string, data: Partial<User>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'users', id);
  await updateDoc(docRef, { ...data, updatedAt: serverTimestamp() });
};

// --- FETCH FUNCTIONS ---

export const getStudentsByTeacher = async (teacherId: string): Promise<Student[]> => {
  if (!db) return [];
  const q = query(collection(db, 'siswa'), where('teacherId', '==', teacherId));
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
};

export const getReportsByTeacher = async (teacherId: string): Promise<Report[]> => {
  if (!db) return [];
  const q = query(collection(db, 'laporan'), where('teacherId', '==', teacherId));
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Report));
};

// --- REALTIME LISTENERS ---

export const subscribeToStudentsByTeacher = (
  teacherId: string, 
  onUpdate: (students: Student[]) => void
): Unsubscribe => {
  if (!db) return () => {}; 
  const q = query(collection(db, 'siswa'), where('teacherId', '==', teacherId));
  return onSnapshot(q, (snapshot) => {
    const students = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
    onUpdate(students);
  });
};

export const subscribeToReportsByTeacher = (
  teacherId: string,
  onUpdate: (reports: Report[]) => void
): Unsubscribe => {
  if (!db) return () => {};
  const q = query(collection(db, 'laporan'), where('teacherId', '==', teacherId));
  return onSnapshot(q, (snapshot) => {
    const reports = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Report));
    onUpdate(reports);
  });
};

export const addStudent = async (student: Omit<Student, 'id' | 'attendance' | 'behaviorScore'>): Promise<Student> => {
  if (!db) throw new Error("Firestore not initialized");
  const level = extractClassLevel(student.className);
  const docRef = await addDoc(collection(db, 'siswa'), { ...student, classLevel: level, attendance: 100, behaviorScore: 10, createdAt: serverTimestamp() });
  return { id: docRef.id, ...student, classLevel: level, attendance: 100, behaviorScore: 10, createdAt: new Date().toISOString() } as Student;
};

export const updateStudent = async (id: string, data: Partial<Student>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'siswa', id);
  const updateData = { ...data };

  if (data.className) {
    (updateData as any).classLevel = extractClassLevel(data.className);
  }

  await updateDoc(docRef, updateData);
};

export const addReport = async (report: Omit<Report, 'id' | 'createdAt'>): Promise<Report> => {
  if (!db) throw new Error("Firestore not initialized");
  const batch = writeBatch(db);
  const newReportRef = doc(collection(db, 'laporan'));
  const createdAt = new Date().toISOString();
  batch.set(newReportRef, { ...report, createdAt });

  const studentRef = doc(db, 'siswa', report.studentId);
  const latestProgress = report.tahfizh.individual.split(' - ')[1] || report.tahfizh.individual;
  batch.update(studentRef, { 
    currentProgress: latestProgress,
    ...(report.totalHafalan ? { totalHafalan: report.totalHafalan } : {})
  });

  await batch.commit();
  return { id: newReportRef.id, ...report, createdAt } as Report;
};

export const getAllStudents = async (): Promise<Student[]> => {
  if (!db) return [];
  const snapshot = await getDocs(collection(db, 'siswa'));
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { User, Role } from '../../../types';
import { getAllTeachers, addTeacher, updateTeacher } from '../../../services/firestoreService';
import { Users, ChevronRight, Mail, Plus, X, ShieldCheck, Edit2 } from 'lucide-react';
import { Button } from '../../../components/Button';

export default function CoordinatorGuruPage() {
  const [teachers, setTeachers] = useState<User[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [newName, setNewName] = useState('');
  const [newNickname, setNewNickname] = useState('');
  const [newEmail, setNewEmail] = useState('');
  const [newRole, setNewRole] = useState<Role>('GURU');

  const navigate = useNavigate();

  useEffect(() => {
    loadTeachers();
  }, []);

  const loadTeachers = () => {
    getAllTeachers()
      .then(data => {
        setTeachers(Array.isArray(data) ? data : []);
      })
      .catch(err => {
        console.error("Failed to load teachers", err);
        setTeachers([]);
      });
  };

  const handleOpenAddModal = () => {
    setEditingId(null);
    setNewName('');
    setNewNickname('');
    setNewEmail('');
    setNewRole('GURU');
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (e: React.MouseEvent, teacher: User) => {
    e.stopPropagation(); // Mencegah navigasi ke halaman detail
    setEditingId(teacher.id);
    setNewName(teacher.name);
    setNewNickname(teacher.nickname || '');
    setNewEmail(teacher.email);
    setNewRole(teacher.role);
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName || !newEmail || !newNickname) return;

    setIsSubmitting(true);
    try {
      if (editingId) {
        // Mode Edit
        await updateTeacher(editingId, {
          name: newName,
          nickname: newNickname,
          email: newEmail,
          role: newRole
        });
      } else {
        // Mode Tambah
        await addTeacher(newName, newEmail, newNickname, newRole);
      }

      await loadTeachers(); // Refresh list from Firestore
      setIsModalOpen(false);
    } catch (error) {
      console.error("Failed to save teacher", error);
      alert("Gagal menyimpan data ke database.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Data Guru & Staf</h2>
          <p className="text-gray-500 mt-1">Daftar semua guru halaqah and koordinator.</p>
        </div>
        <Button onClick={handleOpenAddModal}>
          <Plus size={18} className="mr-2" /> Tambah Guru
        </Button>
      </div>

      {!teachers || teachers.length === 0 ? (
        <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
           <p className="text-gray-500">Belum ada data guru.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {teachers.map((teacher, index) => {
            if (!teacher) return null;

            const name = typeof teacher.name === 'string' ? teacher.name : "Tanpa Nama";
            const nickname = typeof teacher.nickname === 'string' && teacher.nickname ? teacher.nickname : name;
            const email = teacher.email || "-";
            const role = teacher.role || 'GURU';

            const initial = typeof nickname === 'string' && nickname.length > 0 
              ? nickname.charAt(0).toUpperCase() 
              : "?";

            return (
              <div 
                key={teacher.id || `teacher-${index}`} 
                className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 hover:shadow-md transition-shadow cursor-pointer group relative"
                onClick={() => navigate(`/coordinator/guru/${teacher.id}`)}
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg ${role === 'KOORDINATOR' ? 'bg-purple-100 text-purple-600' : 'bg-primary-100 text-primary-600'}`}>
                      {initial}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <h3 className="font-bold text-gray-900 group-hover:text-primary-600 transition-colors">
                          {nickname}
                        </h3>
                        {role === 'KOORDINATOR' && (
                          <ShieldCheck size={14} className="text-purple-600" />
                        )}
                      </div>
                      <p className="text-xs text-gray-500 truncate max-w-[150px]">{name}</p>
                      <div className="flex items-center gap-1.5 text-xs text-gray-500 mt-1">
                        <Mail size={12} />
                        {email}
                      </div>
                    </div>
                  </div>

                  {/* Tombol Edit Baru */}
                  <button 
                    onClick={(e) => handleOpenEditModal(e, teacher)}
                    className="p-2 text-gray-400 hover:text-primary-600 hover:bg-primary-50 rounded-lg transition-colors"
                    title="Edit Profil Guru"
                  >
                    <Edit2 size={16} />
                  </button>
                </div>

                <div className="border-t border-gray-100 pt-4 flex justify-between items-center">
                  <span className="text-sm font-medium text-gray-600">
                    {role === 'KOORDINATOR' ? 'Lihat Profil Admin' : 'Lihat Detail Kelas'}
                  </span>
                  <div className="w-8 h-8 rounded-full bg-gray-50 flex items-center justify-center text-gray-400 group-hover:bg-primary-50 group-hover:text-primary-600 transition-colors">
                    <ChevronRight size={18} />
                  </div>
