          const currentJuzDisplay = (sabaqDisplay !== '-') 
            ? getJuzFromString(sabaqDisplay)
            : (student.currentProgress || "-");

          return {
            ...student,
            latestReport: latest,
            totalHafalanDisplay: hafalanDisplay,
            sabaqDisplay,
            tilawahDisplay,
            currentJuzDisplay
          };
        });

        setStudents(studentsWithStats);
