import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Layout } from './app/layout';
import LoginPage from './app/(auth)/login/page';
import CoordinatorDashboard from './app/coordinator/dashboard/page';
import CoordinatorGuruPage from './app/coordinator/guru/page';
import CoordinatorTeacherDetail from './app/coordinator/guru/[id]/page';
import CoordinatorSiswaPage from './app/coordinator/siswa/page';
import CoordinatorKelasPage from './app/coordinator/kelas/page';
import CoordinatorReportsPage from './app/coordinator/reports/page';
import GuruDashboard from './app/guru/dashboard/page';
import GuruHalaqahPage from './app/guru/halaqah/page';
import GuruLaporanPage from './app/guru/laporan/page';
import GuruViewReportPage from './app/guru/view-report/page';
import GuruEvaluationPage from './app/guru/evaluation/page';
import GuruGradesPage from './app/guru/grades/page';
import GuruRaporPage from './app/guru/rapor/page';
import { getStoredUser, simpleLogout } from './services/simpleAuth';
import { User, Role } from './types';

function App() {
  const [user, setUser] = useState<User | null>(getStoredUser());

  const handleLogin = (newUser: User) => {
    setUser(newUser);
  };

  const handleLogout = () => {
    simpleLogout();
    setUser(null);
  };

  return (
    <HashRouter>
      <Routes>
        {/* Login Page */}
        <Route path="/login" element={
          !user ? <LoginPage onLogin={handleLogin} /> : <Navigate to="/" replace />
        } />

        {/* Protected Routes */}
        <Route element={<Layout user={user} onLogout={handleLogout} />}>

          {/* ROOT REDIRECTOR */}
          <Route path="/" element={
            user?.role === 'KOORDINATOR' 
              ? <Navigate to="/coordinator/dashboard" replace /> 
              : <Navigate to="/guru/dashboard" replace />
          } />

          {/* Coordinator Pages */}
          <Route path="/coordinator/dashboard" element={<CoordinatorDashboard />} />
          <Route path="/coordinator/guru" element={<CoordinatorGuruPage />} />
          <Route path="/coordinator/guru/:id" element={<CoordinatorTeacherDetail />} />
          <Route path="/coordinator/siswa" element={<CoordinatorSiswaPage />} />
          <Route path="/coordinator/kelas" element={<CoordinatorKelasPage />} />
          <Route path="/coordinator/reports" element={<CoordinatorReportsPage />} />

          {/* Guru Pages */}
          <Route path="/guru/dashboard" element={<GuruDashboard teacherId={user?.id} />} />
          <Route path="/guru/halaqah" element={<GuruHalaqahPage teacherId={user?.id} />} />
          <Route path="/guru/laporan" element={<GuruLaporanPage teacherId={user?.id} />} />
          <Route path="/guru/view-report" element={<GuruViewReportPage teacherId={user?.id} />} />
          <Route path="/guru/evaluation" element={<GuruEvaluationPage />} />
          <Route path="/guru/grades" element={<GuruGradesPage />} />
          <Route path="/guru/rapor" element={<GuruRaporPage />} />
        </Route>

        {/* Catch-all */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </HashRouter>
  );
}

export default App;

import { 
  collection, 
  getDocs, 
  addDoc, 
  query, 
  where, 
  doc, 
  getDoc,
  updateDoc,
  deleteDoc,
  serverTimestamp,
  writeBatch,
  onSnapshot,
  Unsubscribe
} from 'firebase/firestore';
import { db } from '../lib/firebase';
import { User, Student, Report, Role } from '../types';
import { extractClassLevel } from './sdqTargets';

export const getAllTeachers = async (): Promise<User[]> => {
  if (!db) return [];
  const snapshot = await getDocs(collection(db, 'users'));
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as User));
};

export const getTeacherById = async (id: string): Promise<User | undefined> => {
  if (!db) return undefined;
  const docRef = doc(db, 'users', id);
  const docSnap = await getDoc(docRef);
  return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } as User : undefined;
};

export const addTeacher = async (name: string, email: string, nickname: string, role: Role): Promise<User> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = await addDoc(collection(db, 'users'), { name, nickname, email, role, createdAt: serverTimestamp() });
  return { id: docRef.id, name, nickname, email, role, createdAt: new Date().toISOString() } as User;
};

export const updateTeacher = async (id: string, data: Partial<User>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'users', id);
  await updateDoc(docRef, { ...data, updatedAt: serverTimestamp() });
};

// --- FETCH FUNCTIONS ---

export const getStudentsByTeacher = async (teacherId: string): Promise<Student[]> => {
  if (!db) return [];
  const q = query(collection(db, 'siswa'), where('teacherId', '==', teacherId));
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
};

export const getReportsByTeacher = async (teacherId: string): Promise<Report[]> => {
  if (!db) return [];
  const q = query(collection(db, 'laporan'), where('teacherId', '==', teacherId));
  const snapshot = await getDocs(q);
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Report));
};

// --- REALTIME LISTENERS ---

export const subscribeToStudentsByTeacher = (
  teacherId: string, 
  onUpdate: (students: Student[]) => void
): Unsubscribe => {
  if (!db) return () => {}; 
  const q = query(collection(db, 'siswa'), where('teacherId', '==', teacherId));
  return onSnapshot(q, (snapshot) => {
    const students = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
    onUpdate(students);
  });
};

export const subscribeToReportsByTeacher = (
  teacherId: string,
  onUpdate: (reports: Report[]) => void
): Unsubscribe => {
  if (!db) return () => {};
  const q = query(collection(db, 'laporan'), where('teacherId', '==', teacherId));
  return onSnapshot(q, (snapshot) => {
    const reports = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Report));
    onUpdate(reports);
  });
};

export const addStudent = async (student: Omit<Student, 'id' | 'attendance' | 'behaviorScore'>): Promise<Student> => {
  if (!db) throw new Error("Firestore not initialized");
  const level = extractClassLevel(student.className);
  const docRef = await addDoc(collection(db, 'siswa'), { ...student, classLevel: level, attendance: 100, behaviorScore: 10, createdAt: serverTimestamp() });
  return { id: docRef.id, ...student, classLevel: level, attendance: 100, behaviorScore: 10, createdAt: new Date().toISOString() } as Student;
};

export const updateStudent = async (id: string, data: Partial<Student>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'siswa', id);
  const updateData = { ...data };

  if (data.className) {
    (updateData as any).classLevel = extractClassLevel(data.className);
  }

  await updateDoc(docRef, updateData);
};

export const addReport = async (report: Omit<Report, 'id' | 'createdAt'>): Promise<Report> => {
  if (!db) throw new Error("Firestore not initialized");
  const batch = writeBatch(db);
  const newReportRef = doc(collection(db, 'laporan'));
  const createdAt = new Date().toISOString();
  batch.set(newReportRef, { ...report, createdAt });

  const studentRef = doc(db, 'siswa', report.studentId);
  const latestProgress = report.tahfizh.individual.split(' - ')[1] || report.tahfizh.individual;
  batch.update(studentRef, { 
    currentProgress: latestProgress,
    ...(report.totalHafalan ? { totalHafalan: report.totalHafalan } : {})
  });

  await batch.commit();
  return { id: newReportRef.id, ...report, createdAt } as Report;
};

/**
 * Memperbarui data laporan yang sudah ada
 */
export const updateReport = async (reportId: string, data: Partial<Report>): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'laporan', reportId);
  await updateDoc(docRef, { ...data, updatedAt: serverTimestamp() });
};

/**
 * Menghapus data laporan
 */
export const deleteReport = async (reportId: string): Promise<void> => {
  if (!db) throw new Error("Firestore not initialized");
  const docRef = doc(db, 'laporan', reportId);
  await deleteDoc(docRef);
};

export const getAllStudents = async (): Promise<Student[]> => {
  if (!db) return [];
  const snapshot = await getDocs(collection(db, 'siswa'));
  return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Student));
};

import React, { useEffect, useState } from 'react';
import { Report } from '../../../types';
import { subscribeToReportsByTeacher, deleteReport, updateReport } from '../../../services/firestoreService';
import { calculateFromRangeString } from '../../../services/quranMapping';
import { Search, Download, Edit2, Trash2, X, FileSpreadsheet } from 'lucide-react';
import { Button } from '../../../components/Button';
import * as XLSX from 'xlsx';

interface GuruViewReportPageProps {
  teacherId?: string;
}

// Helper: Format Total Hafalan Adaptif (Juz > Halaman > Baris)
const formatTotalHafalan = (total: { juz: number; pages: number; lines: number } | undefined) => {
  if (!total) return '-';

  const j = Number(total.juz || 0);
  const p = Number(total.pages || 0);
  const l = Number(total.lines || 0);

  if (j > 0) return `${j} Juz`;
  if (p > 0) return `${p} Halaman`;
  if (l > 0) return `${l} Baris`;

  return '-'; 
};

export default function GuruViewReportPage({ teacherId = '1' }: GuruViewReportPageProps) {
  const [reports, setReports] = useState<Report[]>([]);
  const [filteredReports, setFilteredReports] = useState<Report[]>([]);
  const [search, setSearch] = useState('');
  const [filterMonth, setFilterMonth] = useState('Semua');
  const [filterType, setFilterType] = useState('Semua');
  const [isLoading, setIsLoading] = useState(true);

  // State untuk Modals
  const [editingReport, setEditingReport] = useState<Report | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);

  // USE REALTIME LISTENER HERE
  useEffect(() => {
    if (!teacherId) return;
    setIsLoading(true);

    const unsubscribe = subscribeToReportsByTeacher(teacherId, (data) => {
      setReports(data);
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, [teacherId]);

  useEffect(() => {
    let result = reports;

    if (search) {
      result = result.filter(r => 
        r.studentName.toLowerCase().includes(search.toLowerCase()) ||
        (r.className || '').toLowerCase().includes(search.toLowerCase())
      );
    }

    if (filterMonth !== 'Semua') {
      result = result.filter(r => r.month === filterMonth);
    }

    if (filterType !== 'Semua') {
      result = result.filter(r => r.type === filterType);
    }

    setFilteredReports(result);
  }, [search, filterMonth, filterType, reports]);

  // Helper to format range string nicely
  const formatRangeDisplay = (rangeStr: string | undefined) => {
    if (!rangeStr || rangeStr === '-' || rangeStr.trim() === '') return "-";

    const parts = rangeStr.split(' - ');
    if (parts.length !== 2) return rangeStr;

    const startPart = parts[0].trim();
    const endPart = parts[1].trim();

    const parse = (s: string) => {
      const match = s.match(/^(.*)[:\s]+(\d+)$/);
      if (match) return { surah: match[1].trim(), ayat: match[2] };
      return null;
    };

    const startObj = parse(startPart);
    const endObj = parse(endPart);

    if (startObj && endObj) {
      if (startObj.surah === endObj.surah) {
        return `${startObj.surah}: ${startObj.ayat}-${endObj.ayat}`;
      } else {
        return `${startPart} - ${endPart}`;
      }
    }

    return rangeStr;
  };

  const getCalculationDisplay = (rangeStr: string | undefined) => {
    if (!rangeStr || rangeStr === '-' || rangeStr === '') return "-";
    const result = calculateFromRangeString(rangeStr);
    if (result.pages > 0) return `${result.pages} Halaman`;
    if (result.lines > 0) return `${result.lines} Baris`;
    return "0 Baris";
  };

  const getStatusBadge = (rangeStr: string | undefined) => {
    if (!rangeStr || rangeStr === '-') {
      return (
        <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-orange-100 text-orange-700 border border-orange-200">
          Belum Tercapai
        </span>
      );
    }

    const result = calculateFromRangeString(rangeStr);
    const targetPages = 1; 

    if (result.pages >= targetPages) {
      return (
        <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-green-100 text-green-700 border border-green-200">
          Tercapai
        </span>
      );
    } else {
      return (
        <span className="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-orange-100 text-orange-700 border border-orange-200">
          Belum Tercapai
        </span>
      );
    }
  };

  const handleExportExcel = () => {
    if (filteredReports.length === 0) return;

    // Persiapkan data untuk export Excel
    const exportData = filteredReports.map((report, idx) => ({
      "No": idx + 1,
      "Nama Siswa": report.studentName,
      "Kelas": report.className || '',
      "Jumlah Hafalan": formatTotalHafalan(report.totalHafalan),
      "Tilawah Individual": report.tilawah.individual,
      "Tilawah Klasikal": report.tilawah.classical,
      "Hasil Tilawah": getCalculationDisplay(report.tilawah.individual !== '-' ? report.tilawah.individual : report.tilawah.classical),
      "Tahfizh Individual": report.tahfizh.individual,
      "Tahfizh Klasikal": report.tahfizh.classical,
      "Hasil Tahfizh": getCalculationDisplay(report.tahfizh.individual !== '-' ? report.tahfizh.individual : report.tahfizh.classical),
      "Catatan": report.notes
    }));

    // Generate workbook
    const worksheet = XLSX.utils.json_to_sheet(exportData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Laporan Halaqah");

    // Tulis file
    const fileName = `Laporan_Halaqah_${new Date().toISOString().split('T')[0]}.xlsx`;
    XLSX.writeFile(workbook, fileName);
  };

  const handleDeleteReport = async (reportId: string) => {
    if (!window.confirm("Apakah Anda yakin ingin menghapus laporan ini? Data yang dihapus tidak dapat dikembalikan.")) return;

    setIsDeleting(true);
    try {
      await deleteReport(reportId);
    } catch (error) {
      alert("Gagal menghapus laporan.");
    } finally {
      setIsDeleting(false);
    }
  };

  const handleOpenEdit = (report: Report) => {
    setEditingReport({ ...report });
    setIsEditModalOpen(true);
  };

  const handleUpdateReport = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingReport) return;

    setIsLoading(true);
    try {
      await updateReport(editingReport.id, {
        notes: editingReport.notes,
        tilawah: editingReport.tilawah,
        tahfizh: editingReport.tahfizh
      });
      setIsEditModalOpen(false);
      setEditingReport(null);
    } catch (error) {
      alert("Gagal memperbarui laporan.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-6 max-w-[95%] mx-auto pb-12">
      <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Lihat Laporan</h2>
          <p className="text-gray-500 mt-1">Arsip laporan perkembangan siswa.</p>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 flex flex-col lg:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
          <input 
            type="text" 
            placeholder="Cari nama siswa..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 outline-none"
          />
        </div>

        <div className="flex gap-4 overflow-x-auto pb-2 lg:pb-0">
          <select 
            value={filterMonth}
            onChange={(e) => setFilterMonth(e.target.value)}
