export interface AyahPointer {
  surah: string;
  ayah: number;
}

export interface CalculationResult {
  pages: number;
  lines: number;
  juz: number;
  isPartial: boolean;
  error?: string;
}

export interface SurahMeta {
  index: number; // Index asli Mushaf (1-114)
  name: string;
  totalAyah: number;
  startPage: number;
  endPage: number;
}

import { AyahPointer, CalculationResult } from './types';
import { QURAN_METADATA } from './quranData';
import { SDQ_SURAH_ORDER } from './sdqCurriculum';

export class TahfizhEngine {
  /**
   * Menghitung capaian berdasarkan kurikulum SDQ.
   * Menangani Juz 30 terbalik dan Juz 29-26 forward.
   */
  static calculateRange(start: AyahPointer, end: AyahPointer): CalculationResult {
    try {
      // 1. Bersihkan Nama Surah (hapus prefiks angka jika ada)
      const cleanStartSurah = this.normalizeSurahName(start.surah);
      const cleanEndSurah = this.normalizeSurahName(end.surah);

      // 2. Temukan index di kurikulum SDQ
      const startIndex = SDQ_SURAH_ORDER.indexOf(cleanStartSurah);
      const endIndex = SDQ_SURAH_ORDER.indexOf(cleanEndSurah);

      if (startIndex === -1 || endIndex === -1) {
        return { pages: 0, lines: 0, juz: 0, isPartial: true, error: "Surah tidak ditemukan di kurikulum SDQ" };
      }

      // Pastikan urutan benar (start <= end di array kurikulum)
      if (startIndex > endIndex) {
         // Balik jika user input terbalik dari urutan kurikulum
         return this.calculateRange(end, start);
      }

      // 3. Identifikasi jalur surah yang dilewati
      const surahPath = SDQ_SURAH_ORDER.slice(startIndex, endIndex + 1);

      let totalLines = 0;

      surahPath.forEach((surahName, index) => {
        const meta = QURAN_METADATA[surahName];
        if (!meta) return;

        const isFirstSurah = index === 0;
        const isLastSurah = index === surahPath.length - 1;

        // Tentukan batas ayat untuk surah ini
        let sAyah = isFirstSurah ? start.ayah : 1;
        let eAyah = isLastSurah ? end.ayah : meta.totalAyah;

        // Validasi Ayat
        if (sAyah > meta.totalAyah) sAyah = meta.totalAyah;
        if (eAyah > meta.totalAyah) eAyah = meta.totalAyah;

        // Hitung proporsi baris Mushaf (15 baris per halaman)
        const totalPagesInSurah = meta.endPage - meta.startPage + 1;
        const totalLinesInSurah = totalPagesInSurah * 15;

        // Asumsi distribusi ayat merata per baris (pendekatan standar pendidikan)
        const ayatsCovered = Math.max(0, eAyah - sAyah + 1);
        const completionRatio = ayatsCovered / meta.totalAyah;
        const linesEarned = totalLinesInSurah * completionRatio;

        totalLines += linesEarned;
      });

      // 4. Konversi Baris ke Halaman & Juz (Standard: 20 Hal = 1 Juz)
      const finalPages = Math.floor(totalLines / 15);
      const remainingLines = Math.round(totalLines % 15);
      const decimalJuz = parseFloat((totalLines / (15 * 20)).toFixed(2));

      return {
        pages: finalPages,
        lines: remainingLines,
        juz: decimalJuz,
        isPartial: false
      };
    } catch (error) {
      console.error("Tahfizh Engine Fatal Error:", error);
      return { pages: 0, lines: 0, juz: 0, isPartial: true };
    }
  }

  private static normalizeSurahName(name: string): string {
    return name.replace(/^\d+\.\s*/, '').trim();
  }
}

import { TahfizhEngine } from './tahfizh/engine';
import { QURAN_METADATA } from './tahfizh/quranData';

export const QURAN_MAPPING = Object.values(QURAN_METADATA).map(m => ({
  page: m.startPage,
  surah: m.name,
  start: 1,
  end: m.totalAyah
}));

export const IQRA_MAPPING = [
  { volume: 1, pages: 31 },
  { volume: 2, pages: 30 },
  { volume: 3, pages: 30 },
  { volume: 4, pages: 30 },
  { volume: 5, pages: 30 },
  { volume: 6, pages: 31 },
];

const getIqraVolume = (surahName: string): number | null => {
  const match = surahName.match(/iqra\s*'?\s*(\d+)/i);
  if (match) return parseInt(match[1]);
  return null;
};

const getIqraAbsolutePage = (volume: number, page: number): number => {
  let absolute = 0;
  for (let i = 0; i < volume - 1; i++) {
    absolute += IQRA_MAPPING[i].pages;
  }
  return absolute + page;
};

/**
 * RE-ROUTED: Menggunakan TahfizhEngine untuk akurasi kurikulum SDQ
 */
export const calculateHafalan = (
  fromSurah: string, 
  fromAyat: number, 
  toSurah: string, 
  toAyat: number
): { pages: number, lines: number } => {
  if (!fromSurah || !toSurah) return { pages: 0, lines: 0 };

  const fromIqraVol = getIqraVolume(fromSurah);
  const toIqraVol = getIqraVolume(toSurah);

  // Jika Iqra, gunakan logika linear lama
  if (fromIqraVol !== null && toIqraVol !== null) {
    const startAbs = getIqraAbsolutePage(fromIqraVol, fromAyat);
    const endAbs = getIqraAbsolutePage(toIqraVol, toAyat);
    const diff = endAbs - startAbs + 1;
    return { pages: Math.max(0, diff), lines: 0 };
  }

  // Jika Al-Quran, gunakan TahfizhEngine yang menghargai urutan SDQ
  const result = TahfizhEngine.calculateRange(
    { surah: fromSurah, ayah: fromAyat },
    { surah: toSurah, ayah: toAyat }
  );

  return { pages: result.pages, lines: result.lines };
};

export const calculateFromRangeString = (rangeStr: string): { pages: number, lines: number } => {
  if (!rangeStr || rangeStr.trim() === '-' || rangeStr.trim() === '') return { pages: 0, lines: 0 };

  let parts = rangeStr.split(' - ').map(s => s.trim());
  if (parts.length !== 2) {
      const strictParts = rangeStr.split('-');
      if (strictParts.length === 2) parts = strictParts.map(s => s.trim());
      else return { pages: 0, lines: 0 };
  }

  const parseLocation = (s: string) => {
    const match = s.match(/^(.*?)[:\s]+(\d+)$/);
    if (match) return { surah: match[1].trim(), ayah: parseInt(match[2]) };
    return null;
  };

  const start = parseLocation(parts[0]);
  const end = parseLocation(parts[1]);

  if (start && end) return calculateHafalan(start.surah, start.ayah, end.surah, end.ayat);
  return { pages: 0, lines: 0 };
};

import { TahfizhEngine } from './tahfizh/engine';
import { QURAN_METADATA } from './tahfizh/quranData';

export const QURAN_MAPPING = Object.values(QURAN_METADATA).map(m => ({
  page: m.startPage,
  surah: m.name,
  start: 1,
  end: m.totalAyah
}));

export const IQRA_MAPPING = [
  { volume: 1, pages: 31 },
  { volume: 2, pages: 30 },
  { volume: 3, pages: 30 },
  { volume: 4, pages: 30 },
  { volume: 5, pages: 30 },
  { volume: 6, pages: 31 },
];

const getIqraVolume = (surahName: string): number | null => {
  const match = surahName.match(/iqra\s*'?\s*(\d+)/i);
  if (match) return parseInt(match[1]);
  return null;
};

const getIqraAbsolutePage = (volume: number, page: number): number => {
  let absolute = 0;
  for (let i = 0; i < volume - 1; i++) {
    absolute += IQRA_MAPPING[i].pages;
  }
  return absolute + page;
};

/**
 * RE-ROUTED: Menggunakan TahfizhEngine untuk akurasi kurikulum SDQ
 */
export const calculateHafalan = (
  fromSurah: string, 
  fromAyat: number, 
  toSurah: string, 
  toAyat: number
): { pages: number, lines: number } => {
  if (!fromSurah || !toSurah) return { pages: 0, lines: 0 };

  const fromIqraVol = getIqraVolume(fromSurah);
  const toIqraVol = getIqraVolume(toSurah);

  // Jika Iqra, gunakan logika linear lama
  if (fromIqraVol !== null && toIqraVol !== null) {
    const startAbs = getIqraAbsolutePage(fromIqraVol, fromAyat);
    const endAbs = getIqraAbsolutePage(toIqraVol, toAyat);
    const diff = endAbs - startAbs + 1;
    return { pages: Math.max(0, diff), lines: 0 };
  }

  // Jika Al-Quran, gunakan TahfizhEngine yang menghargai urutan SDQ
  const result = TahfizhEngine.calculateRange(
    { surah: fromSurah, ayah: fromAyat },
    { surah: toSurah, ayah: toAyat }
  );

  return { pages: result.pages, lines: result.lines };
};

export const calculateFromRangeString = (rangeStr: string): { pages: number, lines: number } => {
  if (!rangeStr || rangeStr.trim() === '-' || rangeStr.trim() === '') return { pages: 0, lines: 0 };

  let parts = rangeStr.split(' - ').map(s => s.trim());
  if (parts.length !== 2) {
      const strictParts = rangeStr.split('-');
      if (strictParts.length === 2) parts = strictParts.map(s => s.trim());
      else return { pages: 0, lines: 0 };
  }

  const parseLocation = (s: string) => {
    const match = s.match(/^(.*?)[:\s]+(\d+)$/);
    if (match) return { surah: match[1].trim(), ayah: parseInt(match[2]) };
    return null;
  };

  const start = parseLocation(parts[0]);
  const end = parseLocation(parts[1]);

  // Fix: Corrected property 'ayat' to 'ayah' as defined in the return type of parseLocation
  if (start && end) return calculateHafalan(start.surah, start.ayah, end.surah, end.ayah);
  return { pages: 0, lines: 0 };
};

