             <ArrowLeft size={20} className="mr-2"/> Kembali ke Daftar
           </button>
           <Button onClick={() => window.print()} className="bg-emerald-600 hover:bg-emerald-700">
             <Printer size={18} className="mr-2"/> Cetak Rapor
           </Button>
