              <div className="text-right mb-12">
                 Bogor, {viewingReport.dateHijri || '... Hijriah'}<br/>
                 {viewingReport.dateStr || '... Masehi'}
              </div>
              <div className="grid grid-cols-2 gap-40 text-center">
                 <div>
                    <div className="mb-20">Orang Tua/Wali</div>
