              >
                <ChevronRight size={24} />
              </button>
           </div>

           <div className="flex gap-2">
             <Button variant="outline" onClick={() => handleEditReport(selectedStudent)} className="border-blue-200 text-blue-600 hover:bg-blue-50">
               <Edit2 size={18} className="mr-1"/> Edit
